pragma solidity ^0.8.0;

contract ProxyObf {
    address private _x;
    address private _y;

    constructor(address z) {
        _x = msg.sender;
        _y = z;
    }

    fallback() external payable {
        address a = _y;
        assembly {
            calldatacopy(0, 0, calldatasize())
            let b := delegatecall(gas(), a, 0, calldatasize(), 0, 0)
            let c := returndatasize()
            returndatacopy(0, 0, c)
            switch b
            case 0 { revert(0, c) }
            default { return(0, c) }
        }
    }

    function changeImpl(address d) external {
        require(msg.sender == _x, "not admin");
        _y = d;
    }
}

contract ImplObf {
    address public o;

    function setOwner(address p) external {
        o = p;
